// Try to get all open tabs using browser APIs
const tabCount = document.target ? window.navigator.tabs ? window.navigator.tabs.length : "unknown";
console.log("navigator.tabs length:", tabCount);

// Try chrome.tabs API if available
try {
  const tabs = await chrome.tabs.get({ active: false });
  tabs.forEach((tab, i) => {
    console.log(`Tab ${i}: id=${tab.id}, url=${tab.url}, title=${tab.title}`);
  });
} catch (e) {
  console.log("chrome.tabs API not available:", e.message);
}

// Also try to get visible tab titles from the UI
const allTabs = document.querySelectorAll('[role="tab"], .tab, .tab-item, [class*="tab"]');
console.log("DOM tab elements found:", allTabs.length);
allTabs.forEach((el, i) => {
  console.log(`DOM Tab ${i}: text=${el.textContent || el.innerText}, class=${el.className}`);
});
